'use strict';

const crypto = require('crypto');

/**
 * Generate cryptographically secure PKCE code verifier
 * RFC 7636: 43-128 characters from [A-Za-z0-9-._~]
 * 32 random bytes → 43 base64url characters → ~258 bits entropy
 *
 * @returns {string} Base64-URL encoded random string (43 characters)
 */
function generateCodeVerifier() {
  return crypto.randomBytes(32).toString('base64url');
}

/**
 * Compute PKCE code challenge using S256 method
 * RFC 7636: BASE64URL(SHA256(ASCII(code_verifier)))
 *
 * @param {string} codeVerifier - The code verifier to hash
 * @returns {string} Base64-URL encoded SHA256 hash
 */
function generateCodeChallenge(codeVerifier) {
  return crypto.createHash('sha256')
    .update(codeVerifier)
    .digest('base64url');
}

/**
 * Generate both verifier and challenge together
 * Convenience function that creates both PKCE values
 *
 * @returns {Object} Object containing codeVerifier and codeChallenge
 */
function generatePkceChallenge() {
  const verifier = generateCodeVerifier();
  const challenge = generateCodeChallenge(verifier);
  return { codeVerifier: verifier, codeChallenge: challenge };
}

module.exports = {
  generateCodeVerifier,
  generateCodeChallenge,
  generatePkceChallenge
};
